#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long A,B,C,P,Q,R; scanf("%lld %lld %lld %lld %lld %lld",&A,&B,&C,&P,&Q,&R);
        long long total = P+Q+R;
        long long cur = A+B+C;
        int ok = (2*cur > total);
        if(!ok){
            long long h1 = P + B + C;
            long long h2 = A + Q + C;
            long long h3 = A + B + R;
            if(2*h1 > total || 2*h2 > total || 2*h3 > total) ok = 1;
        }
        puts(ok?"YES":"NO");
    }
    return 0;
}

